mapper.select:
select YYYYMM, SEL_CODE, SITE as SITE_ORG, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' end as SITE, MODEL, MODEL_TYPE, STOCK, BOH, [INPUT], [OUT], EOH, INPUT_ETC, INPUT_MOVING, INPUT_PROD, OUT_SHEET, OUT_RETURN, OUT_INVOICE, OUT_ETC, OUT_MOVING from DOI_STOCK where 1=1
and yyyymm = #{yyyymm}
and site = #{site}
order BY MODEL;

DROP TABLE IF EXISTS #TempTable1;

CREATE TABLE #TempTable1 (
	YYYYMM varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	SEL_CODE varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
