	MODEL nvarchar(50) COLLATE Korean_Wansung_CI_AS NOT NULL,
	MODEL_TYPE nvarchar(50) COLLATE Korean_Wansung_CI_AS NOT NULL,
	STOCK nvarchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	BOH int NULL,
	[INPUT] int NULL,
	[OUT] int NULL,
	EOH int NULL,
	INPUT_ETC int NULL,
	INPUT_MOVING int NULL,
	INPUT_PROD int NULL,
	OUT_SHEET int NULL,
	OUT_RETURN int NULL,
	OUT_INVOICE int NULL,
	OUT_ETC int NULL,
	OUT_MOVING int NULL
);

