INSERT INTO DOI_STOCK (YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, STOCK, BOH, [INPUT], [OUT], EOH, INPUT_ETC, INPUT_MOVING, INPUT_PROD, OUT_SHEET, OUT_RETURN, OUT_INVOICE, OUT_ETC, OUT_MOVING)
SELECT YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, STOCK, BOH, [INPUT], [OUT], EOH, INPUT_ETC, INPUT_MOVING, INPUT_PROD, OUT_SHEET, OUT_RETURN, OUT_INVOICE, OUT_ETC, OUT_MOVING
FROM (
	SELECT *, MAX(seq_no) over (partition by YYYYMM, SITE, MODEL) max_seq_no FROM #TempTable
) A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_STOCK b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SITE = a.SITE
	AND b.MODEL = a.MODEL
);

DROP TABLE #TempTable;

INSERT INTO DOI_MODEL_MAST
(
YYYYMM
, SEL_CODE
, SITE
, MODEL
, MODEL_TYPE
, STOCK
, BOH
, [INPUT]
, [OUT]
, EOH
, INPUT_ETC
, INPUT_MOVING
, INPUT_PROD
, OUT_SHEET
, OUT_RETURN
, OUT_INVOICE
, OUT_ETC
, OUT_MOVING
)
VALUES
(
#{yyyymm}
, #{selCode}
, CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='베트남' then 'VN' else left(#{site},2) end
, #{model}
, #{modelType}
, #{stock}
, #{boh}
, #{input}
, #{out}
, #{eoh}
, #{inputEtc}
, #{inputMoving}
, #{inputProd}
, #{outSheet}
, #{outReturn}
, #{outInvoice}
, #{outEtc}
, #{outMoving}
);

mapper.delete:
