SET SEL_CODE = #{selCode}
,SITE = #{site}
,MODEL = #{model}
,MODEL_TYPE = #{modelType}
,STOCK = #{stock}
,BOH = #{boh}
,[INPUT] = #{input}
,[OUT] = #{out}
,EOH = #{eoh}
,INPUT_ETC = #{inputEtc}
,INPUT_MOVING = #{inputMoving}
,INPUT_PROD = #{inputProd}
,OUT_SHEET = #{outSheet}
,OUT_RETURN = #{outReturn}
,OUT_INVOICE = #{outInvoice}
,OUT_ETC = #{outEtc}
,OUT_MOVING = #{outMoving}
WHERE 1=1
and yyyymm = #{yyyymm}
and site = #{siteOrg}
and model = #{model}
;
